ring.setAttribute('role','img'); ring.setAttribute('aria-label',Math.round(ratio*100)+' percent complete'); ring.appendChild(make('span','ring-value',valid?Math.round(ratio*100)+'%':'—')); heading.appendChild(ring);
const copy=make('div','heading-copy'); copy.appendChild(make('div','eyebrow','Achievement badges')); copy.appendChild(make('h2','',title));
const summary=valid?(value.toLocaleString()+' of '+target.toLocaleString()+' '+(data.unit?String(data.unit):'complete')):(badges.length+' badges');
copy.appendChild(make('div','meta',data.summary?String(data.summary):summary)); heading.appendChild(copy); frame.appendChild(heading);
if(!badges.length){
  frame.appendChild(make('div','empty','Add badge definitions to show achievements.'));
}else{
  const grid=make('div','grid');
  badges.forEach((badge) => {
    const earned=badge&&badge.earned===true; const progress=Number(badge&&badge.progress); const badgeTarget=Number(badge&&badge.target);
    const hasProgress=Number.isFinite(progress)&&Number.isFinite(badgeTarget)&&badgeTarget>0; const badgeRatio=earned?1:(hasProgress?Math.max(0,Math.min(1,progress/badgeTarget)):0);
    const card=make('article','badge '+(earned?'earned':'locked'));
    card.appendChild(make('div','medal',badge&&badge.icon?String(badge.icon):(earned?'★':'◇')));
    const status=make('div','status');
    if(earned) status.appendChild(make('span','pill ok','✓ Earned'));
    else if(hasProgress&&progress>0) status.appendChild(make('span','pill partial','Partial'));
    else status.appendChild(make('span','pill no','✗ Locked'));
    card.appendChild(status); card.appendChild(make('h3','',badge&&badge.label!=null?String(badge.label):'Untitled badge'));
    if(badge&&badge.description) card.appendChild(make('p','description',String(badge.description)));
    const progressBox=make('div','progress'); const progressRow=make('div','progress-row'); progressRow.appendChild(make('span','',earned?'Completed':'Progress to unlock'));
    const unit=badge&&badge.unit?' '+String(badge.unit):'';
    progressRow.appendChild(make('span','',earned?'100%':(hasProgress?progress.toLocaleString()+' / '+badgeTarget.toLocaleString()+unit:'Not started'))); progressBox.appendChild(progressRow);
    const track=make('div','track'); const fill=make('div','fill'); fill.style.width=(badgeRatio*100)+'%'; track.appendChild(fill); progressBox.appendChild(track); card.appendChild(progressBox);
